from flask import Flask, request, jsonify
import pandas as pd
import tensorflow as tf
from tensorflow import keras
from tensorflow.keras import layers
import os

app = Flask(__name__)
model = None

def create_model(input_shape, num_classes):
    model = keras.Sequential([
        layers.Conv2D(32, (3, 3), activation='relu', input_shape=input_shape),
        layers.MaxPooling2D(pool_size=(2, 2)),
        layers.Conv2D(64, (3, 3), activation='relu'),
        layers.MaxPooling2D(pool_size=(2, 2)),
        layers.Flatten(),
        layers.Dense(128, activation='relu'),
        layers.Dense(num_classes, activation='softmax')
    ])
    model.compile(optimizer='adam', loss='sparse_categorical_crossentropy', metrics=['accuracy'])
    return model

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    if file and file.filename.endswith('.csv'):
        file_path = os.path.join('uploads', file.filename)
        file.save(file_path)
        train_model(file_path)
        return jsonify({'message': 'File uploaded and model trained successfully'}), 200
    return jsonify({'error': 'Invalid file type'}), 400

def train_model(csv_file):
    global model
    data = pd.read_csv(csv_file)
    images = data['image_path'].values
    labels = data['label'].values
    num_classes = len(set(labels))
    
    # Load and preprocess images
    image_data = []
    for img_path in images:
        img = keras.preprocessing.image.load_img(img_path, target_size=(64, 64))
        img_array = keras.preprocessing.image.img_to_array(img)
        image_data.append(img_array)
    image_data = tf.convert_to_tensor(image_data) / 255.0
    
    if model is None:
        model = create_model((64, 64, 3), num_classes)
    
    model.fit(image_data, labels, epochs=10)

@app.route('/contribute', methods=['POST'])
def contribute_example():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    if file and file.filename.endswith('.jpg'):
        file_path = os.path.join('uploads', file.filename)
        file.save(file_path)
        # Here you would save the label for the image, e.g., in a database
        return jsonify({'message': 'Image contributed successfully'}), 200
    return jsonify({'error': 'Invalid file type'}), 400

if __name__ == '__main__':
    os.makedirs('uploads', exist_ok=True)
    app.run(debug=True)